#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=2003,INF=1e8;

int n,m,d[4][2]={{0,-1},{0,1},{1,0},{-1,0}};
pair<int,int> st;
char s[N][N];
bool b[N][N];

int main(){
    while(cin>>n>>m){
        for(int i=0;i<n;i++){
            scanf("%s",s[i]);
            for(int j=0;j<m;j++){
            	b[i][j]=0;
                if(s[i][j]=='S')
                    st=make_pair(i,j);
            }
        }
        bool flag=0;
        queue<pair<int,int>> q;
        unordered_set<long long> to;
        q.push(st);
        b[st.x][st.y]=1;
        to.insert(1LL*st.x*INF+st.y);
        while(q.size()){
            pair<int,int> p=q.front();
            q.pop();
            if(b[(p.x%n+n)%n][(p.y%m+m)%m] && (p.x<0 || p.x>=n || p.y<0 || p.y>=m)){
                flag=1;
                break;
            }
            for(int i=0;i<4;i++){
                pair<int,int> nxt=make_pair(p.x+d[i][0],p.y+d[i][1]);
                if(s[(nxt.x%n+n)%n][(nxt.y%m+m)%m]!='#' && to.find(1LL*nxt.x*INF+nxt.y)==to.end()){
                    q.push({nxt.x,nxt.y}),to.insert(1LL*nxt.x*INF+nxt.y);
                    //printf("(%d, %d) -> (%d, %d)\n",p.x,p.y,nxt.x,nxt.y);
                    if(0<=nxt.x && nxt.x<n && 0<=nxt.y && nxt.y<m)
                        b[nxt.x][nxt.y]=1;
                }
            }
        }
        if(flag)
            puts("Yes");
        else
            puts("No");
    }
}
